    /**
     * @ch 產生 Mock SpinAck 假資料
     * @description USE_MOCK_SERVER=true 時，跳過實際 server 回傳，直接注入假盤面
     */
    public GenerateMockSpinAck(): any {
        if (!Game_Define.USE_MOCK_SERVER) return null;

        const col = Game_Define.COL;
        const row = Game_Define.ROW;
        const symbolCount = Game_Define.SYMBOL_COUNT;

        // 產生隨機盤面（排除 server-only 和 blank）
        const maxSymbol = 22; // SC_SUPER 以下為可見符號
        const plate: number[][] = [];
        for (let c = 0; c < col; c++) {
            const colArr: number[] = [];
            for (let r = 0; r < row; r++) {
                colArr.push(Math.floor(Math.random() * maxSymbol));
            }
            plate.push(colArr);
        }

        // Mock 基礎回傳
        const ack: any = {
            Result: 0,
            RoundWin: 0,
            Balance: 10000,
            Plate: plate,
            WinLines: [],
            RoundQueue: [{ Plate: plate, WinLines: [], RoundWin: 0 }],
            IsGoingToFree: false,
            FreeGameCount: 0,
            FreeGameTotal: 0,
        };

        // 依 MOCK_MODE 調整
        switch (Game_Define.MOCK_MODE) {
            case "freegame":
                ack.IsGoingToFree = true;
                ack.FreeGameCount = 0;
                ack.FreeGameTotal = 10;
                // 強制放 3 顆 SC_EXPAND
                ack.Plate[0][0] = 18; // SC_EXPAND
                ack.Plate[2][1] = 18;
                ack.Plate[4][2] = 18;
                break;
            case "scatter":
                // 放 2 顆 scatter 測 NearWin
                ack.Plate[0][0] = 21; // SC_SUPER
                ack.Plate[1][1] = 21;
                break;
            case "bigwin":
                ack.RoundWin = 5000;
                ack.RoundQueue[0].RoundWin = 5000;
                break;
        }

        log("[Mock] GenerateMockSpinAck mode=" + Game_Define.MOCK_MODE);
        return ack;
    }

    /**
     * @ch 初始化 Mock 鍵盤快捷鍵（開發用）
     * @description F1=normal, F2=freegame, F3=scatter, F4=bigwin
     */
    public InitMockKeyboard(): void {
        if (!Game_Define.USE_MOCK_SERVER) return;

        input.on(Input.EventType.KEY_DOWN, (event: EventKeyboard) => {
            switch (event.keyCode) {
                case KeyCode.F1:
                    Game_Define.MOCK_MODE = "normal";
                    log("[Mock] 切換模式: normal");
                    break;
                case KeyCode.F2:
                    Game_Define.MOCK_MODE = "freegame";
                    log("[Mock] 切換模式: freegame");
                    break;
                case KeyCode.F3:
                    Game_Define.MOCK_MODE = "scatter";
                    log("[Mock] 切換模式: scatter");
                    break;
                case KeyCode.F4:
                    Game_Define.MOCK_MODE = "bigwin";
                    log("[Mock] 切換模式: bigwin");
                    break;
            }
        });
        log("[Mock] 鍵盤快捷鍵已啟用 (F1~F4)");
    }
    //#endregion Mock Server
}

