import { Enum, color } from "cc";
import { newBottombarManager } from "db://astarte-framework/Managers";

enum GAMEVIEW_STATE
{
    WAIT_READY,
    PLATE_SHOW,
    FEATURE_SHOW,
    UNSHOW_PREPARE,
    AWARD,
    ROUND_SHOW_END,
    ROUND_END,

    EFFECT_START,
    // CHECK_JP,
    SCATTER_SHOW,
    ENTER_FREE,
    FULL_REWARD,
    LEAVE_FREE,
    ADD_FREE,

    /**@ch 消除狀態（Cascade/Tumble 用） */
    EXPLODE,
    /**@ch 補位狀態（Cascade/Tumble 用） */
    MATCHING_PATCH_UP,
}

//需與SlotReels的symbol擺放順序相同
export enum Symbol
{
    /**百搭*/
    WILD,       // 0
    /**馬蹄鐵*/
    M1,         // 1
    /**豎琴*/
    M2,         // 2
    /**蘑菇*/
    M3,         // 3
    /**A*/
    A,          // 4
    /**K*/
    K,          // 5
    /**Q*/
    Q,          // 6
    /**J*/
    J,          // 7
    /**10*/
    Ten,        // 8
    /**收集*/
    COLLECT,    // 9
    /**現金_銅*/
    CASH_BRONZE,// 10
    /**現金_銀*/
    CASH_SILVER,// 11
    /**現金_金*/
    CASH_GOLD,  // 12
    /**彩金 Mini*/
    JP_MINI,    // 13
    /**彩金 Minor*/
    JP_MINOR,   // 14
    /**彩金 Major*/
    JP_MAJOR,   // 15
    /**彩金 Mega*/
    JP_MEGA,    // 16
    /**彩金 Grand*/
    JP_GRAND,   // 17
    /**奪寶_綠（擴張）*/
    SC_EXPAND,  // 18
    /**奪寶_紫（乘倍）*/
    SC_MULTI,   // 19
    /**奪寶_紅（炸彈）*/
    SC_BOMB,    // 20
    /**奪寶_彩虹（飛全盆）*/
    SC_SUPER,   // 21
    /**炸彈事件*/
    FEAT_BOMB,  // 22
    /**加轉事件*/
    FEAT_ADD_SPIN, // 23
    /**空格*/
    BLANK,      // 24
    /**Server用 1*/
    SERVER1,    // 25
    /**Server用 2*/
    SERVER2,    // 26
    /**Server用 3*/
    SERVER3,    // 27
}

export enum AddEffectPrefabs
{
    /**中獎框*/
    FX_FRAME,
    /**金幣特效*/
    SCATTER_FX
}

export class SymbolInfo
{
    /**@ch 符號ID*/
    Symbol: number;

    /**@ch 符號值*/
    Value: number;

    /**@ch JP類型*/
    JpType: number;
}

export enum GAME_EVENT {
    DEVICE_ROTATION = "GAME_EVENT_DEVICE_ROTATION",
    CHANGE_BET = "GAME_EVENT_CHANGE_BET",
}

export default class Game_Define
{
    // ─── Mock Server ───
    static USE_MOCK_SERVER = false;
    static MOCK_MODE: "normal" | "freegame" | "scatter" | "bigwin" = "normal";
    // ─── End Mock Server ───

    static Ver: string = "Ver";
    static SPICY_LEVEL = 2;
    static Symbol = Enum( Symbol );
    static GameState = Enum( GAMEVIEW_STATE );

    /**@ch For盤面壓黑 */
    static Color = {
        Light: color( 255, 255, 255 ),
        Dark: color( 101.25, 94.5, 73.5 ),
    };

    /**@ch 取得當前BET，會受extraBet影響 */
    static GetNowBetValue()
    {
        return newBottombarManager.GetNowBetValue();
    }

    /************************** 多語系 **************************/
    static BUY_BONUS_TXT = [
        "Txt_Buy_Feature_Bet",
        "Txt_Buy_Feature_Title",
        "BuyBonus_IconName",
    ];

    static COL = 5;
    static ROW = 3;
    static SeparateLineWidth = 0; // pixels
    static MAX_ROW = 5; // 最大行數 (FG EXPAND 特色 3x5 → 5x5)
    static SYMBOL_COUNT = 28;

    static SymbolHeight = 82;
    static SymbolWidth = 96;

    static NODE_PREFIX_NAME = [
        "low",
        "",
        "up"
    ];

    static THOUSAND = 1000;
    static MILLION = 1000000;

    /**@ch 飛行特效種類*/
    static FLY_TYPES = 4;

    /**@ch Effect表演分層數(4)，視各遊戲需求*/
    static EFFECT_LAYER_NUMS = 4;
    static LAYERS = {
        ONE: 0,
        TWO: 1,
        THREE: 2,
        FOUR: 3,
    };

    /**@ch 遊戲中須創造之表演大分類，(以此三幣瑞龍為例，symbol算一種、飛行特效算一種、盤面共用中獎特效算一種，共三種) */
    static EFFECT_TYPES = 3;
    static EFFECT_TYPE = {
        SYMBOL: 0,
        ADD_EFFECT: 1,
        FLY: 2,
    };

    static ADD_EFFECT_TYPE = {
        MG: 0,
        FG: 1
    };

    static BIG_NUM = 999999;

    /**@ch 部分表演DELAY時長*/
    static ACTION_DELAY_TIME = {
        TIME_FOR_AWARD_LINE_EFFECT: 1.5,
        FG_FIRST_NEAR_WIN_TIME: 1.1,
        FG_IN_NEAR_WIN_TIME: 0.5
    };
    //
    static AWARD_TYPE = {
        AWARD_TYPE_NON: 0x0,  // 沒中獎(0)
        AWARD_TYPE_LINE: 0x1, // 中獎(1)
        AWARD_TYPE_ALL_PLATE: 0x2,// 全盤(2)

        AWARD_TYPE_MAX: 0x7fff
    };
    static SpeedUp = 1;

    static ActualFlyTime = 0.5;
    static WaitTime = 0.75;
    static HitTime = 0.15;

    static PlateEftOdds = [ 1, 3, 6, 15, 30 ];

    // ─── NearWin / Scatter Config ───
    // codegen 依規格書調整以下常數

    /** 觸發 NearWin 的 Scatter 門檻（幾列有 Scatter 時開始延遲） */
    static NEARWIN_COLLECT_COUNT = 2;
    /** 哪個 Symbol 是 Scatter（codegen: SC_SUPER 作為 NearWin 計數代表） */
    static SCATTER_SYMBOL = Symbol.SC_SUPER;
    /** 所有 Scatter 類符號（三色 + Super） */
    static SCATTER_SYMBOLS = [Symbol.SC_EXPAND, Symbol.SC_MULTI, Symbol.SC_BOMB, Symbol.SC_SUPER];
    /** 盤面格子總數 */
    static FULL_PLATE_NUM = 15;
    /** 哪些列可能出現 Scatter（通常全部列；由 COL 衍生，非全列的遊戲自行覆寫） */
    static SCATTER_COLUMNS: number[] = Array.from( { length: Game_Define.COL }, ( _, i ) => i );
    /** NearWin 觸發後，後續各列多轉的圈數（依序遞增） */
    static SCATTER_NEARWIN_SPIN_TABLE: number[] = [5, 9, 14, 20];
    /** NearWin 觸發後，後續各列的轉速倍率 */
    static NEARWIN_SPIN_SPEED_TABLE: number[] = [1.05, 1.1, 1.2, 1.3];
    // ─── End NearWin Config ───

    static SERVER_RET_TYPE = {
        SERVER_SUCCESS: 0, //正常				
        SERVER_ERROR_SEATE: 799, // 錯誤狀態				
        SERVER_NOUSE: 899, // 無用				
        SERVER_MAINTAIN: 998, // 維護中				
        SERVER_SHUTDOWN: 999, // 關機中				
        SERVER_NEED_UID: 1001, //需要UID				
        SERVER_NEED_LOGIN: 1002, //沒有玩家				
        SERVER_TOKEN_ERROR: 1003, //TOKEN 錯誤				
    };
    static LOGIN_RESULT_TYPE = {
        LOGIN_SUCCESS: 0, //登入成功
        LOGIN_FAIL: 1, // 登入失敗
        API_VERIFY_FAIL: 2001,   // TOKEN驗證失敗
        API_LOGIN_REPEAT_FAIL: 2002,    // 重複登入
    };
    static HEART_BEAT_STATE = {
        NOTIFY: 97, //SERVER 通知訊息
        MAINTAIN: 98, //SERVER 維護中
        CLOSE: 99, //SERVER 關閉
    };
    static StringKey = {
        MC_FEATURES_LEFT: "MC_FEATURES_LEFT",
        MC_FEATURES_RIGHT: "MC_FEATURES_RIGHT",
        FREE_GAME_NAME_STRING: "FREE_GAME_NAME_STRING",
    };

    static ShowDisplayValue: ( value: number ) => number = null;

    /**@ch 特色遊玩押注 */
    static FeatureBetValue = 10;

    static OnExit()
    {
        this.ShowDisplayValue = null;
    }
}

